const GOOGLE_SHEETS = [
  // 'Test data',  // Uncomment for testing
  'Animal', 'Bench', 'Planter', 'Fountain', 'Lamppost', 'Bathtub', 'Sink', 'Vanity', 'Fireplace', 'Table', 'Statue', 'MarbleSlab',
  '2026Instock', 'DoorSurround', 'Wall-Coverings', 'Exterior-Wall-Decoration', 'MarbleRangeHood', 'Moulding', 'StoneMosaicTile', 'MarbleMedallion'
];

return GOOGLE_SHEETS
  .filter(Boolean)  // Remove any empty/null values
  .map(sheet_name => ({ json: { sheet_name } }));

const sheetName = $('🔁 Iterate Sheets').item.json.sheet_name ?? '';

const normalizeDimensions = (data) => ({
  length:    data['Length Inch']    ?? '',
  width:     data['Width Inch']     ?? '',
  height:    data['Height Inch']    ?? '',
  depth:     data['Depth Inch']     ?? '',
  thickness: data['Thickness Inch'] ?? '',
});

return items
  .map(({ json }) => {
    const imageUrl = (json['IMAGE URL3'] ?? '').toString().trim();
    if (
      !json ||
      json.Generate_Title_Description !== 'yes' ||
      (json.Title_Shopify && json.Description_Shopify) ||
      !imageUrl.startsWith('http')
    ) return null;

    return {
      json: {
        row_number: json.row_number ?? 0,
        sheet_name: sheetName,
        keyword:    json['Keywords (Luna)'] ?? '',
        material:   json.Material ?? '',
        finish:     json.Finish   ?? '',
        dimensions: normalizeDimensions(json),
        Image_Url:  json['IMAGE URL3'],
        promptRules: json.Prompt_Rules ?? '',
      },
    };
  })
  .filter(Boolean);

// ============================================
// CONTEXT
// ============================================
const { sheet_name, row_number } =
  $('🔁 Iterate Products for AI Analysis').item.json;

// ============================================
// UTILITIES
// ============================================

const cleanText = (text = '') =>
  String(text)
    .replace(/\s+/g, ' ')
    .trim();

// ============================================
// MAIN
// ============================================

const outputItems = items
  .map(({ json }) => {

    // ----------------------------------------
    // RAW AI OUTPUT
    // ----------------------------------------
    const raw =
      json?.content?.parts?.[0]?.text?.trim();

    if (!raw) return null;

    let parsed;

    try {

      // ----------------------------------------
      // SAFETY CLEANING
      // Handles accidental ```json fences
      // ----------------------------------------
      const cleaned = raw
        .replace(/```json/g, '')
        .replace(/```/g, '')
        .trim();

      parsed = JSON.parse(cleaned);

    } catch (err) {

      // ----------------------------------------
      // RETURN DEBUG INFO IF PARSING FAILS
      // ----------------------------------------
      return {
        json: {
          sheet_name,
          row_number,
          parsing_error: true,
          parsing_error_message: err.message,
          raw_output: raw
        }
      };
    }

    // ========================================
    // SUCCESS OUTPUT
    // ========================================
    return {
      json: {

        sheet_name,
        row_number,

        // ------------------------------------
        // SHOPIFY
        // ------------------------------------
        Title_Shopify: cleanText(
          parsed?.version1?.title
        ),

        Description_Shopify: cleanText(
          parsed?.version1?.description
        ),

        // ------------------------------------
        // ETSY
        // ------------------------------------
        Title_Etsy: cleanText(
          parsed?.version2?.title
        ),

        Description_Etsy: cleanText(
          parsed?.version2?.description
        ),

        // ------------------------------------
        // SEO
        // ------------------------------------
        Shopify_SEO_Title: cleanText(
          parsed?.seo?.title
        ),

        Shopify_SEO_Description: cleanText(
          parsed?.seo?.meta_description
        ),

        // ------------------------------------
        // STATUS
        // ------------------------------------
        Generate_Title_Description: 'no'
      }
    };

  })
  .filter(Boolean);

return outputItems;
